   469→```
   470→
   471→### 6.12. `system/files_persisted` — Files Uploaded (CLI → Server)
   472→
   473→```typescript
   474→interface SDKFilesPersistedEvent {
   475→  type: "system";
   476→  subtype: "files_persisted";
   477→  files: { filename: string; file_id: string }[];
