  1097→  state: "idle" | "connecting" | "reconnecting" | "connected" | "closing" | "closed";
  1098→  headers: Record<string, string>;
  1099→  sessionId: string | undefined;
  1100→  reconnectAttempts: number;
  1101→  messageBuffer: CircularBuffer;  // capacity: 1000
  1102→
  1103→  async connect(): Promise<void>;
  1104→  sendLine(data: string): boolean;
