## 2. HTTP Server Implementation

**File:** `server/http-server.ts`

```typescript
import { EventEmitter } from 'events'
import { serve } from 'bun'
import { logger } from './logger.js'

interface HttpServerConfig {
  port: number
  eventBus: EventEmitter
}

export async function createHttpServer(config: HttpServerConfig) {
  // SSE clients
  const sseClients = new Set<WebSocket>()

  // Store session state reference (set by ws-handler)
  let sessionManager: any = null

  const server = serve({
    port: config.port,
    async fetch(req) {
      const url = new URL(req.url)

      // CORS headers
      const corsHeaders = {
        'Access-Control-Allow-Origin': '*',
        'Access-Control-Allow-Methods': 'GET, POST, OPTIONS',
        'Access-Control-Allow-Headers': 'Content-Type'
      }

      if (req.method === 'OPTIONS') {
        return new Response(null, { headers: corsHeaders })
      }

      // Route: Serve dashboard
      if (url.pathname === '/' || url.pathname === '/index.html') {
        const html = await Bun.file('./dashboard/index.html').text()
        return new Response(html, {
          headers: { 'Content-Type': 'text/html', ...corsHeaders }
        })
      }

      // Route: API endpoints
      if (url.pathname.startsWith('/api/')) {
        return handleApiRequest(url, req, corsHeaders)
      }

      // Route: SSE events
      if (url.pathname === '/api/events') {
        return handleSSE(req, corsHeaders)
      }

      return new Response('Not Found', { status: 404 })
    }
  })

  // Listen to events and broadcast to SSE clients
  config.eventBus.on('assistant', (data) => {
    broadcastSSE({ type: 'assistant', data })
  })

  config.eventBus.on('stream_event', (data) => {
    broadcastSSE({ type: 'stream_event', data })
  })

  config.eventBus.on('result', (data) => {
    broadcastSSE({ type: 'result', data })
  })

  config.eventBus.on('permission_request', (data) => {
    broadcastSSE({ type: 'permission_request', data })
  })

  config.eventBus.on('tool_progress', (data) => {
    broadcastSSE({ type: 'tool_progress', data })
  })

  function broadcastSSE(event: any) {
    // In a real implementation, you'd queue these for each SSE client
    logger.debug('SSE broadcast:', event.type)
  }

  async function handleApiRequest(
    url: URL,
    req: Request,
    corsHeaders: Record<string, string>
  ): Promise<Response> {
    const path = url.pathname

    try {
      // GET /api/status
      if (path === '/api/status' && req.method === 'GET') {
        const status = sessionManager?.getStatus() || {
          connected: false,
          sessionId: null
        }
        return jsonResponse(status, corsHeaders)
      }

      // POST /api/send
      if (path === '/api/send' && req.method === 'POST') {
        const body = await req.json()
        const success = sendToClaude(body.message)
        return jsonResponse({ success }, corsHeaders)
      }

      // POST /api/permission
      if (path === '/api/permission' && req.method === 'POST') {
        const body = await req.json()
        sessionManager?.respondToPermission(body.request_id, body.decision)
        return jsonResponse({ success: true }, corsHeaders)
      }

      // POST /api/interrupt
      if (path === '/api/interrupt' && req.method === 'POST') {
        sendInterrupt()
        return jsonResponse({ success: true }, corsHeaders)
      }

      // GET /api/history
      if (path === '/api/history' && req.method === 'GET') {
        const history = sessionManager?.getHistory() || []
        return jsonResponse({ messages: history }, corsHeaders)
      }

      return new Response('Not Found', { status: 404 })

    } catch (error) {
      logger.error('API error:', error)
      return jsonResponse(
        { error: 'Internal server error' },
        corsHeaders,
        500
      )
    }
  }

  function jsonResponse(
    data: any,
    headers: Record<string, string>,
    status = 200
  ): Response {
    return new Response(JSON.stringify(data), {
      status,
      headers: {
        'Content-Type': 'application/json',
        ...headers
      }
    })
  }

  function sendToClaude(message: string): boolean {
    // This would call the ws-handler's sendToCLI method
    logger.info('Sending to Claude:', message)
    return true
  }

  function sendInterrupt(): void {
    // Send interrupt control request
    logger.info('Sending interrupt')
  }

  function handleSSE(req: Request, corsHeaders: Record<string, string>): Response {
    const headers = {
      'Content-Type': 'text/event-stream',
      'Cache-Control': 'no-cache',
      'Connection': 'keep-alive',
      ...corsHeaders
    }

    const stream = new ReadableStream({
      start(controller) {
        const encoder = new TextEncoder()

        // Send initial connection event
        controller.enqueue(
          encoder.encode(`event: connect\ndata: {"connected":true}\n\n`)
        )

        // Listen for events
        const listener = (event: any) => {
          controller.enqueue(
            encoder.encode(`event: message\ndata: ${JSON.stringify(event)}\n\n`)
          )
        }

        config.eventBus.on('assistant', listener)
        config.eventBus.on('stream_event', listener)
        config.eventBus.on('result', listener)
        config.eventBus.on('permission_request', listener)
        config.eventBus.on('tool_progress', listener)

        // Cleanup on close
        req.signal.addEventListener('abort', () => {
          config.eventBus.off('assistant', listener)
          config.eventBus.off('stream_event', listener)
          config.eventBus.off('result', listener)
          config.eventBus.off('permission_request', listener)
          config.eventBus.off('tool_progress', listener)
          controller.close()
        })
      }
    })

    return new Response(stream, { headers })
  }

  return server
}
