## 5. Start Scripts

### 5.1 Start All (PowerShell)

**File:** `scripts/start-all.ps1`

```powershell
# Start all services for the Voice-to-Claude-Code bridge

$ErrorActionPreference = "Stop"

Write-Host "Starting Claude Code Voice Bridge..." -ForegroundColor Cyan

# Check if .env exists
if (!(Test-Path .env)) {
    Write-Host "ERROR: .env file not found!" -ForegroundColor Red
    Write-Host "Copy .env.example to .env and configure your credentials."
    exit 1
}

# Start WebSocket + HTTP server
Write-Host "Starting WebSocket server (port 8765) and HTTP server (port 3001)..." -ForegroundColor Yellow
$serverJob = Start-Job -ScriptBlock {
    cd $using:PWD
    bun run server/index.ts
}

# Wait a bit for server to start
Start-Sleep -Seconds 2

# Start Claude Code CLI
Write-Host "Starting Claude Code CLI with --sdk-url..." -ForegroundColor Yellow
$claudeJob = Start-Job -ScriptBlock {
    cd $using:PWD
    claude --sdk-url ws://localhost:8765 --print --output-format stream-json --input-format stream-json --verbose -p ""
}

# Wait for Claude to connect
Start-Sleep -Seconds 3

# Start LiveKit Agent
Write-Host "Starting LiveKit voice agent..." -ForegroundColor Yellow
$agentJob = Start-Job -ScriptBlock {
    cd $using:PWD
    cd agent
    python voice_agent.py dev
}

# Open dashboard
Write-Host "Opening dashboard..." -ForegroundColor Green
Start-Process "http://localhost:3001"

Write-Host ""
Write-Host "All services started!" -ForegroundColor Green
Write-Host "Dashboard: http://localhost:3001" -ForegroundColor Cyan
Write-Host ""
Write-Host "Press Ctrl+C to stop all services" -ForegroundColor Yellow

# Wait for Ctrl+C
try {
    while ($true) {
        Start-Sleep -Seconds 1

        # Check if jobs are still running
        if ($serverJob.State -ne "Running") {
            Write-Host "Server job stopped unexpectedly" -ForegroundColor Red
            break
        }
        if ($claudeJob.State -ne "Running") {
            Write-Host "Claude CLI job stopped" -ForegroundColor Yellow
        }
        if ($agentJob.State -ne "Running") {
            Write-Host "Agent job stopped unexpectedly" -ForegroundColor Red
            break
        }
    }
} finally {
    Write-Host ""
    Write-Host "Stopping all services..." -ForegroundColor Yellow

    Stop-Job $serverJob
    Stop-Job $claudeJob
    Stop-Job $agentJob

    Remove-Job $serverJob
    Remove-Job $claudeJob
    Remove-Job $agentJob

    Write-Host "All services stopped." -ForegroundColor Green
}
