{
  "name": "voice-claude-bridge",
  "version": "1.0.0",
  "type": "module",
  "scripts": {
    "start": "bun run server/index.ts",
    "start:server": "bun run server/index.ts",
    "start:all": "powershell -ExecutionPolicy Bypass -File scripts/start-all.ps1",
    "dev": "bun --watch server/index.ts",
    "test": "bun test",
    "lint": "eslint server/"
  },
  "dependencies": {
    "ws": "^8.18.0",
    "dotenv": "^16.4.5"
  },
  "devDependencies": {
    "@types/ws": "^8.5.10",
    "@types/node": "^20.12.12",
    "eslint": "^9.0.0",
    "bun-types": "^1.1.0"
  }
}

export const logger = {
  debug: (...args: unknown[]) => {
    if (process.env.LOG_LEVEL === 'debug') {
      console.log('[DEBUG]', ...args)
    }
  },
  info: (...args: unknown[]) => {
    console.log('[INFO]', ...args)
  },
  warn: (...args: unknown[]) => {
    console.warn('[WARN]', ...args)
  },
  error: (...args: unknown[]) => {
    console.error('[ERROR]', ...args)
  }
}

import { EventEmitter } from 'events'

interface ToolCall {
  toolUseId: string
  toolName: string
  input: Record<string, unknown>
  status: 'pending' | 'approved' | 'denied' | 'executing' | 'completed' | 'failed'
  result?: unknown
  error?: string
  timestamp: number
  elapsed?: number
}

interface PermissionRequest {
  request_id: string
  tool_use_id: string
  tool_name: string
  input: Record<string, unknown>
  description?: string
  timestamp: number
  decision?: 'allow' | 'deny' | 'pending'
}

interface Message {
  direction: 'in' | 'out'
  type: string
  timestamp: number
  data: unknown
  id?: string
}

interface SessionConfig {
  sessionId: string
  model: string
  tools: string[]
  permissionMode: string
  cwd: string
  version?: string
}

export class SessionManager extends EventEmitter {
  private sessionId: string | null = null
  private model: string | null = null
  private tools: string[] = []
  private permissionMode: string = 'default'
  private cwd: string = ''
  private status: 'idle' | 'processing' | 'waiting_permission' = 'idle'
  private messages: Message[] = []
  private toolCalls: ToolCall[] = []
  private pendingPermissions: Map<string, PermissionRequest> = new Map()
  private permissionDecisions: Map<string, { behavior: 'allow' | 'deny'; updatedInput: Record<string, unknown> }> = new Map()
  private firstMessage: Record<string, unknown> | null = null
  private result: any = null
  private usage: {
    totalTokens: number
    totalCostUSD: number
    turnCount: number
  } = {
    totalTokens: 0,
    totalCostUSD: 0,
    turnCount: 0
  }

  constructor(eventBus: EventEmitter) {
    super()
    this.eventBus = eventBus
  }

  private eventBus: EventEmitter

  init(config: SessionConfig): void {
    this.sessionId = config.sessionId
    this.model = config.model
    this.tools = config.tools
    this.permissionMode = config.permissionMode
    this.cwd = config.cwd
    this.status = 'idle'

    this.info = {
      connected: true,
      sessionId: config.sessionId,
      model: config.model,
      tools: config.tools,
      permissionMode: config.permissionMode,
      cwd: config.cwd
    }

    this.eventBus.emit('system_init', this.info)
  }

  private info: any = {}

  getStatus(): any {
    return {
      connected: !!this.sessionId,
      sessionId: this.sessionId,
      status: this.status,
      model: this.model,
      tools: this.tools,
      permissionMode: this.permissionMode,
      cwd: this.cwd,
      pendingPermission: this.pendingPermissions.size > 0 ? Array.from(this.pendingPermissions.values())[0] : null,
      messageHistory: this.messages,
      toolCalls: this.toolCalls,
      usage: this.usage
    }
  }

  addMessage(message: Message): void {
    this.messages.push(message)
    if (this.messages.length > 1000) {
      this.messages.shift()
    }
  }

  getHistory(): Message[] {
    return this.messages
  }

  addToolCall(toolCall: Omit<ToolCall, 'status'> & { status?: ToolCall['status'] }): void {
    this.toolCalls.push({
      ...toolCall,
      status: toolCall.status || 'pending'
    })
    this.eventBus.emit('tool_call', toolCall)
  }

  updateToolCall(toolUseId: string, status: ToolCall['status'], extra?: Partial<ToolCall>): void {
    const toolCall = this.toolCalls.find(t => t.toolUseId === toolUseId)
    if (toolCall) {
      toolCall.status = status
      if (extra) {
        Object.assign(toolCall, extra)
      }
      this.eventBus.emit('tool_progress', {
        tool_use_id: toolUseId,
        tool_name: toolCall.toolName,
        status,
        elapsed: toolCall.elapsed
      })
    }
  }

  addPendingPermission(request: PermissionRequest): void {
    this.pendingPermissions.set(request.tool_use_id, request)
    this.status = 'waiting_permission'
    this.eventBus.emit('permission_request', request)
  }

  getPermissionDecision(toolUseId: string): { behavior: 'allow' | 'deny'; updatedInput: Record<string, unknown> } | null {
    return this.permissionDecisions.get(toolUseId) || null
  }

  respondToPermission(toolUseId: string, decision: 'allow' | 'deny', updatedInput?: Record<string, unknown>): void {
    this.permissionDecisions.set(toolUseId, {
      behavior: decision,
      updatedInput: updatedInput || {}
    })

    const pending = this.pendingPermissions.get(toolUseId)
    if (pending) {
      pending.decision = decision
      this.eventBus.emit('permission_response', {
        request_id: pending.request_id,
        decision
      })
    }

    this.status = 'processing'
  }

  queueFirstMessage(message: Record<string, unknown>): void {
    this.firstMessage = message
  }

  getFirstMessage(): Record<string, unknown> | null {
    const msg = this.firstMessage
    this.firstMessage = null
    return msg
  }

  setResult(result: any): void {
    this.result = result
    this.status = 'idle'
    if (result.usage) {
      this.usage.totalTokens += (result.usage.input_tokens || 0) + (result.usage.output_tokens || 0)
    }
    if (result.total_cost_usd) {
      this.usage.totalCostUSD += result.total_cost_usd
    }
    if (result.num_turns) {
      this.usage.turnCount += result.num_turns
    }
  }

  setStatus(status: 'idle' | 'processing' | 'waiting_permission'): void {
    this.status = status
    this.eventBus.emit('status_change', { status })
  }
}

// Message type definitions for the Claude Code WebSocket protocol

export interface SDKUserMessage {
  type: "user";
  message: {
    role: "user";
    content: string | ContentBlock[];
  };
  parent_tool_use_id: string | null;
  session_id: string;
  uuid?: string;
  isSynthetic?: boolean;
}

export interface SDKSystemInitMessage {
  type: "system";
  subtype: "init";
  cwd: string;
  session_id: string;
  tools: string[];
  mcp_servers?: { name: string; status: string }[];
  model: string;
  permissionMode: string;
  apiKeySource: string;
  claude_code_version: string;
  slash_commands: string[];
  agents?: string[];
  skills?: string[];
  plugins?: { name: string; path: string }[];
  output_style: string;
  uuid: string;
}

export interface SDKAssistantMessage {
  type: "assistant";
  message: {
    id: string;
    type: "message";
    role: "assistant";
    model: string;
    content: ContentBlock[];
    stop_reason: string | null;
    usage: {
      input_tokens: number;
      output_tokens: number;
      cache_creation_input_tokens: number;
      cache_read_input_tokens: number;
    };
  };
  parent_tool_use_id: string | null;
  error?: string;
  uuid: string;
  session_id: string;
}

export interface SDKStreamEventMessage {
  type: "stream_event";
  event: any;
  parent_tool_use_id: string | null;
  uuid: string;
  session_id: string;
}

export interface SDKResultMessage {
  type: "result";
  subtype: "success" | "error_during_execution" | "error_max_turns" | "error_max_budget_usd" | "error_max_structured_output_retries";
  is_error: boolean;
  result?: string;
  errors?: string[];
  duration_ms: number;
  duration_api_ms: number;
  num_turns: number;
  total_cost_usd: number;
  stop_reason: string | null;
  usage: {
    input_tokens: number;
    output_tokens: number;
    cache_creation_input_tokens: number;
    cache_read_input_tokens: number;
  };
  uuid: string;
  session_id: string;
}

export interface SDKControlRequest {
  type: "control_request";
  request_id: string;
  request: ControlRequestPayload;
}

export interface ControlRequestCanUseTool {
  subtype: "can_use_tool";
  tool_name: string;
  input: Record<string, unknown>;
  permission_suggestions?: PermissionUpdate[];
  blocked_path?: string;
  decision_reason?: string;
  tool_use_id: string;
  agent_id?: string;
  description?: string;
}

export type ControlRequestPayload =
  | ControlRequestCanUseTool
  | { subtype: "interrupt" }
  | { subtype: "set_permission_mode"; mode: string }
  | { subtype: "set_model"; model?: string }
  | { subtype: "initialize" }
  | { subtype: "hook_callback"; callback_id: string; input: any; tool_use_id?: string };

export interface SDKControlResponse {
  type: "control_response";
  response: {
    subtype: "success" | "error";
    request_id: string;
    response?: ControlResponseData;
    error?: string;
  };
}

export interface ControlResponseData {
  behavior: "allow" | "deny";
  updatedInput: Record<string, unknown>;
  message?: string;
  interrupt?: boolean;
  updatedPermissions?: PermissionUpdate[];
}

export interface PermissionUpdate {
  type: "addRules" | "replaceRules" | "removeRules" | "setMode" | "addDirectories" | "removeDirectories";
  rules?: { toolName: string; ruleContent?: string }[];
  behavior?: "allow" | "deny" | "ask";
  mode?: string;
  directories?: string[];
  destination: "userSettings" | "projectSettings" | "localSettings" | "session" | "cliArg";
}

export interface SDKToolProgressMessage {
  type: "tool_progress";
  tool_use_id: string;
  tool_name: string;
  parent_tool_use_id: string | null;
  elapsed_time_seconds: number;
  uuid: string;
  session_id: string;
}

export interface SDKKeepAliveMessage {
  type: "keep_alive";
}

export type ContentBlock =
  | { type: "text"; text: string }
  | { type: "tool_use"; id: string; name: string; input: Record<string, unknown> }
  | { type: "tool_result"; tool_use_id: string; content: string | ContentBlock[]; is_error?: boolean }
  | { type: "thinking"; thinking: string; budget_tokens?: number };

export type SDKMessage =
  | SDKSystemInitMessage
  | SDKAssistantMessage
  | SDKStreamEventMessage
  | SDKResultMessage
  | SDKControlRequest
  | SDKToolProgressMessage
  | SDKKeepAliveMessage;

import { ClaudeWebSocketHandler } from '../ws-handler.js'
import { SessionManager } from '../state/session.js'
import { logger } from '../logger.js'
import type { SDKMessage, SDKControlRequest, ControlRequestCanUseTool } from './messages.js'

export class MessageHandler {
  constructor(private session: SessionManager) {}

  async handle(
    message: SDKMessage,
    handler: ClaudeWebSocketHandler
  ): Promise<void> {
    switch (message.type) {
      case 'system':
        await this.handleSystem(message, handler)
        break

      case 'assistant':
        await this.handleAssistant(message, handler)
        break

      case 'stream_event':
        await this.handleStreamEvent(message, handler)
        break

      case 'result':
        await this.handleResult(message, handler)
        break

      case 'control_request':
        await this.handleControlRequest(message as SDKControlRequest, handler)
        break

      case 'tool_progress':
        await this.handleToolProgress(message, handler)
        break

      case 'keep_alive':
        // Silently consumed
        break

      default:
        logger.warn(`Unhandled message type: ${(message as any).type}`)
    }
  }

  private async handleSystem(message: any, handler: ClaudeWebSocketHandler) {
    if (message.subtype === 'init') {
      logger.info(`System init: session=${message.session_id}, model=${message.model}`)

      this.session.init({
        sessionId: message.session_id,
        model: message.model,
        tools: message.tools,
        permissionMode: message.permissionMode,
        cwd: message.cwd,
        version: message.claude_code_version
      })

      // Send first user message if queued
      const firstMessage = this.session.getFirstMessage()
      if (firstMessage) {
        handler.sendToCLI(firstMessage)
      }
    }
  }

  private async handleAssistant(message: any, handler: ClaudeWebSocketHandler) {
    this.session.addMessage({
      direction: 'in',
      type: 'assistant',
      timestamp: Date.now(),
      data: message
    })

    this.session.setStatus('processing')

    // Extract text for TTS
    const textBlocks = message.message?.content?.filter(
      (b: any) => b.type === 'text'
    ) || []
    const text = textBlocks.map((b: any) => b.text).join('\n')

    // Extract tool uses
    const toolUses = message.message?.content?.filter(
      (b: any) => b.type === 'tool_use'
    ) || []

    for (const toolUse of toolUses) {
      this.session.addToolCall({
        toolUseId: toolUse.id,
        toolName: toolUse.name,
        input: toolUse.input,
        status: 'pending',
        timestamp: Date.now()
      })
    }

    // Broadcast to dashboard
    handler.eventBus.emit('assistant', {
      message,
      text,
      toolUses
    })

    // If text exists, send to TTS via agent
    if (text) {
      handler.eventBus.emit('tts_request', { text })
    }
  }

  private async handleStreamEvent(message: any, handler: ClaudeWebSocketHandler) {
    // Forward streaming text to dashboard
    handler.eventBus.emit('stream_event', message.event)
  }

  private async handleResult(message: any, handler: ClaudeWebSocketHandler) {
    this.session.setResult(message)
    this.session.setStatus('idle')

    handler.eventBus.emit('result', message)
  }

  private async handleControlRequest(
    message: SDKControlRequest,
    handler: ClaudeWebSocketHandler
  ) {
    const { request_id, request } = message

    logger.info(`Control request: ${request.subtype}`, request)

    if (request.subtype === 'can_use_tool') {
      const decision = await this.evaluatePermission(request as ControlRequestCanUseTool)

      const response = {
        type: 'control_response',
        response: {
          subtype: 'success',
          request_id,
          response: decision
        }
      }

      handler.sendToCLI(response)

      // Update tool call status
      this.session.updateToolCall(
        request.tool_use_id,
        decision.behavior === 'allow' ? 'approved' : 'denied'
      )

      // Notify dashboard
      handler.eventBus.emit('permission_response', {
        request_id,
        decision
      })

      // If denied and should interrupt, send interrupt
      if (decision.behavior === 'deny' && decision.interrupt) {
        handler.sendToCLI({
          type: 'control_request',
          request_id: this.generateUUID(),
          request: { subtype: 'interrupt' }
        })
      }
    }
  }

  private async evaluatePermission(request: ControlRequestCanUseTool): Promise<{
    behavior: 'allow' | 'deny'
    updatedInput: Record<string, unknown>
    message?: string
    interrupt?: boolean
  }> {
    const { tool_name, input } = request

    // Check auto-approve list
    const autoApproveTools = process.env.AUTO_APPROVE_TOOLS?.split(',') || []
    if (autoApproveTools.includes(tool_name)) {
      return { behavior: 'allow', updatedInput: input }
    }

    // Check auto-approve patterns
    const autoApprovePatterns = process.env.AUTO_APPROVE_PATTERNS?.split(',') || []
    for (const pattern of autoApprovePatterns) {
      if (this.matchesPattern(tool_name, input, pattern)) {
        return { behavior: 'allow', updatedInput: input }
      }
    }

    // Check dangerous patterns
    const dangerousPatterns = ['rm -rf', 'del /s', 'format', 'shutdown']
    for (const dangerous of dangerousPatterns) {
      if (this.inputContainsDangerous(input, dangerous)) {
        return {
          behavior: 'deny',
          updatedInput: {},
          message: `Dangerous command blocked: ${dangerous}`,
          interrupt: true
        }
      }
    }

    // Default: require manual approval
    this.session.addPendingPermission({
      request_id: request.tool_use_id || this.generateUUID(),
      tool_use_id: request.tool_use_id,
      tool_name,
      input,
      timestamp: Date.now(),
      decision: 'pending'
    })

    // Wait for user decision (with timeout)
    const decision = await this.waitForPermissionDecision(
      request.tool_use_id,
      30000 // 30 second timeout
    )

    return decision || {
      behavior: 'deny',
      updatedInput: {},
      message: 'Permission request timed out',
      interrupt: false
    }
  }

  private matchesPattern(
    toolName: string,
    input: Record<string, unknown>,
    pattern: string
  ): boolean {
    const [tool, cmd] = pattern.split(':')
    if (tool !== toolName) return false
    if (!cmd) return true

    const command = String(input.command || '')
    return command.startsWith(cmd.trim())
  }

  private inputContainsDangerous(
    input: Record<string, unknown>,
    dangerous: string
  ): boolean {
    const command = String(input.command || '')
    return command.toLowerCase().includes(dangerous)
  }

  private async waitForPermissionDecision(
    toolUseId: string,
    timeout: number
  ): Promise<{ behavior: 'allow' | 'deny'; updatedInput: Record<string, unknown> } | null> {
    return new Promise((resolve) => {
      const timer = setTimeout(() => resolve(null), timeout)

      const check = setInterval(() => {
        const decision = this.session.getPermissionDecision(toolUseId)
        if (decision) {
          clearTimeout(timer)
          clearInterval(check)
          resolve(decision)
        }
      }, 100)
    })
  }

  private async handleToolProgress(message: any, handler: ClaudeWebSocketHandler) {
    this.session.updateToolCall(
      message.tool_use_id,
      'executing',
      { elapsed: message.elapsed_time_seconds }
    )

    handler.eventBus.emit('tool_progress', message)
  }

  private generateUUID(): string {
    return 'xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx'.replace(/[xy]/g, (c) => {
      const r = Math.random() * 16 | 0
      const v = c === 'x' ? r : (r & 0x3 | 0x8)
      return v.toString(16)
    })
  }
}

import { WebSocket } from 'ws'
import { EventEmitter } from 'events'
import { logger } from './logger.js'
import { MessageHandler } from './protocol/handlers.js'
import { SessionManager } from './state/session.js'
import type { SDKUserMessage } from './protocol/messages.js'

export class ClaudeWebSocketHandler extends EventEmitter {
  private cliConnection: WebSocket | null = null
  private messageHandler: MessageHandler
  private sessionManager: SessionManager
  public eventBus: EventEmitter

  private messageBuffer: string[] = []
  private reconnectAttempts = 0

  constructor() {
    super()
    this.eventBus = new EventEmitter()
    this.sessionManager = new SessionManager(this.eventBus)
    this.messageHandler = new MessageHandler(this.sessionManager)
  }

  handleConnection(ws: WebSocket): void {
    this.cliConnection = ws
    this.reconnectAttempts = 0
    this.messageBuffer = []

    logger.info('Claude Code CLI connected')

    // Send connection event to dashboard
    this.eventBus.emit('connection', {
      type: 'connected',
      timestamp: Date.now()
    })

    ws.on('message', (data: Buffer) => {
      this.handleMessage(data)
    })

    ws.on('close', (code: number, reason: Buffer) => {
      logger.info(`CLI disconnected: code=${code}, reason=${reason.toString()}`)
      this.cliConnection = null
      this.eventBus.emit('connection', {
        type: 'disconnected',
        code,
        reason: reason.toString()
      })
      this.attemptReconnect()
    })

    ws.on('error', (error: Error) => {
      logger.error('WebSocket error:', error)
    })

    // Start keepalive
    this.startKeepalive()
  }

  private handleMessage(data: Buffer): void {
    // NDJSON: multiple JSON objects separated by newlines
    const text = data.toString()
    const lines = text.split('\n').filter(line => line.trim().length > 0)

    for (const line of lines) {
      try {
        const message = JSON.parse(line)
        logger.debug(`Received: ${message.type}`)

        // Store in buffer for replay on reconnect
        this.messageBuffer.push(line)
        if (this.messageBuffer.length > 1000) {
          this.messageBuffer.shift()
        }

        // Route to appropriate handler
        this.messageHandler.handle(message, this)

      } catch (error) {
        logger.error('Failed to parse message:', line, error)
        this.eventBus.emit('error', {
          type: 'parse_error',
          line,
          error: error instanceof Error ? error.message : String(error)
        })
      }
    }
  }

  sendToCLI(message: Record<string, unknown>): boolean {
    if (!this.cliConnection || this.cliConnection.readyState !== WebSocket.OPEN) {
      logger.warn('Cannot send: CLI not connected')
      return false
    }

    const ndjson = JSON.stringify(message) + '\n'
    this.cliConnection.send(ndjson)
    logger.debug(`Sent: ${message.type}`)

    // Store in buffer
    this.messageBuffer.push(ndjson.trim())

    return true
  }

  sendUserMessage(content: string, sessionId?: string): boolean {
    const userMessage: SDKUserMessage = {
      type: 'user',
      message: {
        role: 'user',
        content
      },
      parent_tool_use_id: null,
      session_id: sessionId || this.sessionManager['sessionId'] || ''
    }

    // If no session yet, queue the message
    if (!this.sessionManager['sessionId']) {
      this.sessionManager.queueFirstMessage(userMessage)
      return true
    }

    return this.sendToCLI(userMessage)
  }

  respondToPermission(requestId: string, decision: 'allow' | 'deny', updatedInput?: Record<string, unknown>): boolean {
    const response = {
      type: 'control_response',
      response: {
        subtype: 'success',
        request_id: requestId,
        response: {
          behavior: decision,
          updatedInput: updatedInput || {}
        }
      }
    }

    return this.sendToCLI(response)
  }

  sendInterrupt(): boolean {
    const interrupt = {
      type: 'control_request',
      request_id: this.generateUUID(),
      request: { subtype: 'interrupt' }
    }

    return this.sendToCLI(interrupt)
  }

  private startKeepalive(): void {
    setInterval(() => {
      if (this.cliConnection?.readyState === WebSocket.OPEN) {
        this.sendToCLI({ type: 'keep_alive' })
      }
    }, 10000) // Every 10 seconds
  }

  private attemptReconnect(): void {
    // Note: CLI will reconnect on its own
    // We just maintain state
    logger.info('Waiting for CLI to reconnect...')
  }

  getSession() {
    return this.sessionManager
  }

  private generateUUID(): string {
    return 'xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx'.replace(/[xy]/g, (c) => {
      const r = Math.random() * 16 | 0
      const v = c === 'x' ? r : (r & 0x3 | 0x8)
      return v.toString(16)
    })
  }
}

import { EventEmitter } from 'events'
import { logger } from './logger.js'
import type { ClaudeWebSocketHandler } from './ws-handler.js'

interface HttpServerConfig {
  port: number
  eventBus: EventEmitter
  getHandler: () => ClaudeWebSocketHandler | null
}

export async function createHttpServer(config: HttpServerConfig) {
  const Bun = await import('bun')

  // Store session state reference
  let sessionManager: any = null

  const server = Bun.serve({
    port: config.port,
    async fetch(req) {
      const url = new URL(req.url)

      // CORS headers
      const corsHeaders = {
        'Access-Control-Allow-Origin': '*',
        'Access-Control-Allow-Methods': 'GET, POST, OPTIONS',
        'Access-Control-Allow-Headers': 'Content-Type'
      }

      if (req.method === 'OPTIONS') {
        return new Response(null, { headers: corsHeaders })
      }

      // Route: Serve dashboard
      if (url.pathname === '/' || url.pathname === '/index.html') {
        try {
          const html = await Bun.file('./dashboard/index.html').text()
          return new Response(html, {
            headers: { 'Content-Type': 'text/html', ...corsHeaders }
          })
        } catch (err) {
          return new Response('Dashboard not found', { status: 404, headers: corsHeaders })
        }
      }

      // Route: API endpoints
      if (url.pathname.startsWith('/api/')) {
        return handleApiRequest(url, req, corsHeaders, config)
      }

      // Route: SSE events
      if (url.pathname === '/api/events') {
        return handleSSE(req, corsHeaders, config)
      }

      return new Response('Not Found', { status: 404, headers: corsHeaders })
    }
  })

  logger.info(`HTTP server listening on port ${config.port}`)
  return server
}

async function handleApiRequest(
  url: URL,
  req: Request,
  corsHeaders: Record<string, string>,
  config: HttpServerConfig
): Promise<Response> {
  const path = url.pathname

  try {
    const handler = config.getHandler()
    if (!handler) {
      return jsonResponse({ error: 'Handler not initialized' }, corsHeaders, 503)
    }

    const session = handler.getSession()

    // GET /api/status
    if (path === '/api/status' && req.method === 'GET') {
      const status = session.getStatus()
      return jsonResponse(status, corsHeaders)
    }

    // POST /api/send
    if (path === '/api/send' && req.method === 'POST') {
      const body = await req.json()
      const success = handler.sendUserMessage(body.message, body.sessionId)
      return jsonResponse({ success }, corsHeaders)
    }

    // POST /api/permission
    if (path === '/api/permission' && req.method === 'POST') {
      const body = await req.json()
      session.respondToPermission(body.tool_use_id || body.request_id, body.decision, body.updatedInput)
      return jsonResponse({ success: true }, corsHeaders)
    }

    // POST /api/interrupt
    if (path === '/api/interrupt' && req.method === 'POST') {
      const success = handler.sendInterrupt()
      return jsonResponse({ success }, corsHeaders)
    }

    // GET /api/history
    if (path === '/api/history' && req.method === 'GET') {
      const history = session.getHistory()
      return jsonResponse({ messages: history }, corsHeaders)
    }

    // GET /health
    if (path === '/health' && req.method === 'GET') {
      return jsonResponse({
        status: 'healthy',
        version: '1.0.0',
        uptime: process.uptime(),
        components: {
          websocketServer: { status: 'up' },
          cliConnection: { status: handler ? 'connected' : 'disconnected' },
          httpServer: { status: 'up' }
        }
      }, corsHeaders)
    }

    return new Response('Not Found', { status: 404, headers: corsHeaders })

  } catch (error) {
    logger.error('API error:', error)
    return jsonResponse(
      { error: 'Internal server error' },
      corsHeaders,
      500
    )
  }
}

function jsonResponse(
  data: any,
  headers: Record<string, string>,
  status = 200
): Response {
  return new Response(JSON.stringify(data), {
    status,
    headers: {
      'Content-Type': 'application/json',
      ...headers
    }
  })
}

function handleSSE(req: Request, corsHeaders: Record<string, string>, config: HttpServerConfig): Response {
  const headers = {
    'Content-Type': 'text/event-stream',
    'Cache-Control': 'no-cache',
    'Connection': 'keep-alive',
    ...corsHeaders
  }

  const stream = new ReadableStream({
    start(controller) {
      const encoder = new TextEncoder()

      // Send initial connection event
      controller.enqueue(
        encoder.encode(`event: connect\ndata: {"connected":true}\n\n`)
      )

      // Listen for events
      const listeners: Array<(event: any) => void> = []

      const eventTypes = ['assistant', 'stream_event', 'result', 'permission_request', 'tool_progress', 'connection', 'system_init', 'permission_response', 'status_change']

      for (const eventType of eventTypes) {
        const listener = (event: any) => {
          controller.enqueue(
            encoder.encode(`event: message\ndata: ${JSON.stringify({ type: eventType, data: event })}\n\n`)
          )
        }
        config.eventBus.on(eventType, listener)
        listeners.push(listener)
      }

      // Cleanup on close
      req.signal.addEventListener('abort', () => {
        for (let i = 0; i < eventTypes.length; i++) {
          config.eventBus.off(eventTypes[i], listeners[i])
        }
        controller.close()
      })
    }
  })

  return new Response(stream, { headers })
}

import { WebSocketServer } from 'ws'
import { createServer } from 'http'
import { ClaudeWebSocketHandler } from './ws-handler.js'
import { createHttpServer } from './http-server.js'
import { logger } from './logger.js'

const WS_PORT = parseInt(process.env.WS_PORT || '8765')
const HTTP_PORT = parseInt(process.env.HTTP_PORT || '3001')

async function main() {
  // Create WebSocket server for Claude Code CLI
  const wsServer = createServer()
  const wss = new WebSocketServer({ server: wsServer })

  let handler: ClaudeWebSocketHandler | null = null

  wss.on('connection', (ws, req) => {
    logger.info('WebSocket connection attempt')

    // Check for Authorization header
    const authHeader = req.headers['authorization']
    if (authHeader && authHeader.startsWith('Bearer ')) {
      logger.info('Connection with Authorization header')
    }

    if (!handler) {
      handler = new ClaudeWebSocketHandler()
    }

    handler.handleConnection(ws)
  })

  wss.on('error', (error) => {
    logger.error('WebSocket server error:', error)
  })

  // Start HTTP server for dashboard and API
  const httpServer = await createHttpServer({
    port: HTTP_PORT,
    eventBus: handler?.eventBus || new (require('events').EventEmitter)(),
    getHandler: () => handler
  })

  // Start listening
  wsServer.listen(WS_PORT, () => {
    logger.info(`WebSocket server listening on port ${WS_PORT}`)
  })

  logger.info(`HTTP server listening on port ${HTTP_PORT}`)
  logger.info(`Dashboard: http://localhost:${HTTP_PORT}`)
  logger.info('')
  logger.info('To start Claude Code CLI, run:')
  logger.info(`  claude --sdk-url ws://localhost:${WS_PORT} --print --output-format stream-json --input-format stream-json --verbose -p ""`)

  // Graceful shutdown
  process.on('SIGTERM', () => {
    logger.info('Shutting down...')
    wss.close()
    httpServer.close()
  })

  process.on('SIGINT', () => {
    logger.info('Shutting down...')
    wss.close()
    httpServer.close()
    process.exit(0)
  })
}

main().catch(console.error)

