        # Check if job is still running
        if ($serverJob.State -ne "Running") {
            Write-Host "Server job stopped unexpectedly" -ForegroundColor Red
            $serverJob | Receive-Job -ErrorAction Variable | Write-Host
            break
        }
    }
} finally {
    Write-Host ""
    Write-Host "Stopping server..." -ForegroundColor Yellow

    Stop-Job $serverJob
    Remove-Job $serverJob

    Write-Host "Server stopped." -ForegroundColor Green
}

# Quick test script to verify the server starts correctly

Write-Host "Testing Claude Code WebSocket Server..." -ForegroundColor Cyan
Write-Host ""

# Create test .env if it doesn't exist
if (!(Test-Path .env)) {
    Write-Host "Creating .env from .env.example..." -ForegroundColor Yellow
    Copy-Item .env.example .env -ErrorAction SilentlyContinue
}

# Start server in background
Write-Host "Starting server..." -ForegroundColor Yellow
$serverProcess = Start-Process -FilePath "bun" -ArgumentList "run", "server/index.ts" -PassThru -NoNewWindow

# Wait for server to start
Start-Sleep -Seconds 3

# Test HTTP endpoint
Write-Host "Testing HTTP server..." -ForegroundColor Yellow
try {
    $response = Invoke-WebRequest -Uri "http://localhost:3001/health" -UseBasicParsing -TimeoutSec 5
    if ($response.StatusCode -eq 200) {
        Write-Host "✓ HTTP server is running!" -ForegroundColor Green
        Write-Host "  Response: $($response.Content)" -ForegroundColor Gray
    } else {
        Write-Host "✗ HTTP server returned status code: $($response.StatusCode)" -ForegroundColor Red
    }
} catch {
    Write-Host "✗ HTTP server test failed: $($_.Exception.Message)" -ForegroundColor Red
}

# Test WebSocket port (simple connection test)
Write-Host ""
Write-Host "Testing WebSocket port..." -ForegroundColor Yellow
try {
    $tcpTest = New-Object System.Net.Sockets.TcpClient
    $tcpTest.Connect("localhost", 8765)
    if ($tcpTest.Connected) {
        Write-Host "✓ WebSocket port 8765 is open!" -ForegroundColor Green
        $tcpTest.Close()
    }
} catch {
    Write-Host "✗ WebSocket port test failed: $($_.Exception.Message)" -ForegroundColor Red
}

# Cleanup
Write-Host ""
Write-Host "Stopping server..." -ForegroundColor Yellow
Stop-Process -Id $serverProcess.Id -Force -ErrorAction SilentlyContinue

Write-Host ""
Write-Host "Test complete!" -ForegroundColor Cyan
Write-Host "To start the server for real, run: bun run start" -ForegroundColor Gray
Write-Host "Then open: http://localhost:3001" -ForegroundColor Gray

